DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextInequalitySetBuilder.pl", "parserGraphTool.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $a = random(-7, 7); InequalitySetBuilder::UseVerticalSuchThat(); Context("InequalitySetBuilder-Only"); $set_builder = Compute("{ x | x >= $a}"); Context("Interval"); $interval = Compute("[$a, inf)"); $gt = GraphTool("{interval,$interval}")->with( availableTools => ['IntervalTool', 'IncludeExcludePointTool'], numberLine => 1, xAxisLabel => 'x', bBox => [ -8, 8 ], ticksDistanceX => 1, minorTicksX => 0, useBracketEnds => 1, showInStatic => 0, showCoordinateHints => 0, );
############################################################ # Body ############################################################
BEGIN_PGML Convert the given set-builder notation into a number line graph and interval notation.
[`[$set_builder]`]
[_]{$gt}{1}
[@KeyboardInstructions('In interval notation:')@]**
[_]{$interval}{12}
END_PGML
